// WRONG: load toàn bộ trước khi update
var expired = await db.Sessions.Where(s => s.ExpiresAt < now).ToListAsync();
foreach (var s in expired) s.Status = "expired";
await db.SaveChangesAsync(); // N roundtrips

// RIGHT: ExecuteUpdateAsync — 1 SQL UPDATE
await db.Sessions
    .Where(s => s.ExpiresAt < now)
    .ExecuteUpdateAsync(setters => setters
        .SetProperty(s => s.Status, "expired")
        .SetProperty(s => s.UpdatedAt, DateTime.UtcNow), ct);

// ExecuteDeleteAsync — 1 SQL DELETE
int deleted = await db.AuditLogs
    .Where(l => l.CreatedAt < cutoff)
    .ExecuteDeleteAsync(ct);

// Kết hợp subquery
await db.Orders
    .Where(o => db.Customers
        .Where(c => c.IsBlocked)
        .Select(c => c.Id)
        .Contains(o.CustomerId))
    .ExecuteDeleteAsync(ct);
